# Merge semantic
all_sem_nodes = chunk1_data["nodes"] + chunk2_data["nodes"]
all_sem_edges = chunk1_data["edges"] + chunk2_data["edges"]
all_sem_hyper = chunk1_data.get("hyperedges",[]) + chunk2_data.get("hyperedges",[])

seen = set()
deduped_nodes = []
for n in all_sem_nodes:
    if n["id"] not in seen:
        seen.add(n["id"])
        deduped_nodes.append(n)

semantic = {"nodes": deduped_nodes, "edges": all_sem_edges, "hyperedges": all_sem_hyper, "input_tokens": 0, "output_tokens": 0}
Path(".graphify_semantic.json").write_text(json.dumps(semantic, indent=2))
print(f"Semantic: {len(deduped_nodes)} nodes, {len(all_sem_edges)} edges")

# Merge AST + semantic
ast = json.loads(Path(".graphify_ast.json").read_text())
seen2 = {n["id"] for n in ast["nodes"]}
merged_nodes = list(ast["nodes"])
for n in semantic["nodes"]:
    if n["id"] not in seen2:
        merged_nodes.append(n)
        seen2.add(n["id"])

merged_edges = ast["edges"] + semantic["edges"]
merged_hyper = semantic.get("hyperedges", [])

merged = {"nodes": merged_nodes, "edges": merged_edges, "hyperedges": merged_hyper, "input_tokens": 0, "output_tokens": 0}
Path(".graphify_extract.json").write_text(json.dumps(merged, indent=2))
print(f"Merged: {len(merged_nodes)} nodes, {len(merged_edges)} edges ({len(ast['nodes'])} AST + {len(deduped_nodes)} semantic)")
